--[[============================================================================
  Luraph Loader (project-reverse mm2.luau) -- Network Analysis Sandbox
  ---------------------------------------------------------------------------
  ЦЕЛЬ: безопасно узнать, ЧТО загрузчик тянет из сети и КУДА шлёт данные.
  Все строки/имена внутри Luraph зашифрованы, статикой не видно, поэтому
  перехват идёт в рантайме через настоящие хуки экзекутора:
    * game:HttpGet / HttpGetAsync / HttpPost / HttpPostAsync   (namecall)
    * HttpService:GetAsync / PostAsync / RequestAsync          (namecall)
    * глобальные request / http_request / syn.request / http.request
    * loadstring / load        -> следующая стадия ПЕРЕХВАТЫВАЕТСЯ, НЕ ЗАПУСК.
    * setclipboard / writefile / appendfile / delfile / makefolder
  Сеть НЕ уходит наружу (block_network=true): URL и тело запроса логируются,
  наружу возвращается безвредная пустышка. Так мы видим вебхук выгрузки
  и его тело (то, что бимер пытался украсть), ничего реально не отправляя.

  !!! ТОЛЬКО ОДНОРАЗОВАЯ ВМ + МУСОРНЫЙ АККАУНТ. Luraph может иметь anti-tamper
      и при обнаружении хуков просто прекратить работу (пустой лог != чисто).

  ЛОГ: экранная панель + файлы luraph_log.txt / luraph_net_capture.txt /
       luraph_stage_capture.lua. Кнопки: Log / Net / Stage2 (копируют в буфер).
============================================================================]]

local CONFIG = {
  block_network  = true,   -- true: сеть не уходит наружу (безопасно)
  run_stages     = true,   -- true: распаковывать — чанки loadstring СОХРАНЯть и ВЫПОЛНЯТЬ
                            -- (чтобы цепочка развернулась; сеть всё равно блокируется)
  log_arg_maxlen = 6000,
}

--// ---- реальные ссылки (сохранить ДО подмен) --------------------------------
local realLoadstring = loadstring
local _getgenv = (type(getgenv) == "function") and getgenv or nil
local realG = (_getgenv and _getgenv()) or getfenv(0) or _G
local function rg(name) return (rawget and pcall(rawget, realG, name)) and rawget(realG, name) or rawget(realG, name) end
local _real_writefile = rawget(realG, "writefile") or writefile
local _real_appendfile = rawget(realG, "appendfile") or appendfile
local _real_setclipboard = rawget(realG, "setclipboard") or setclipboard or toclipboard
local LOG_PATH   = "luraph_log.txt"
local NET_PATH   = "luraph_net_capture.txt"
local STAGE_PATH = "luraph_stage_capture.lua"

--// ---- логгер ---------------------------------------------------------------
local Log = {}
local _alllog, _netlog, _laststage = "", "", nil
local _allstages, _stageN = "", 0
local _guiPush = nil
do
  local n = 0
  local function stamp() n += 1; return string.format("#%04d", n) end
  local function trunc(s)
    if type(s) ~= "string" then return s end
    if #s > CONFIG.log_arg_maxlen then
      return s:sub(1, CONFIG.log_arg_maxlen) .. ("...[+%d bytes]"):format(#s - CONFIG.log_arg_maxlen)
    end
    return s
  end
  local function fmtval(v)
    local t = type(v)
    if t == "string" then return string.format("%q", trunc(v)) end
    if t == "table" then return "<table>" end
    if t == "function" then return "<function>" end
    return tostring(v)
  end
  local function fmtargs(...)
    local parts = {}
    for i = 1, select("#", ...) do parts[i] = fmtval((select(i, ...))) end
    return table.concat(parts, ", ")
  end
  function Log.event(tag, msg, ...)
    local line = string.format("[%s] %s %s", tag, stamp(), msg)
    if select("#", ...) > 0 then line = line .. " :: " .. fmtargs(...) end
    print(line)
    _alllog = _alllog .. line .. "\n"
    if _real_appendfile then pcall(_real_appendfile, LOG_PATH, line .. "\n") end
    if _guiPush then pcall(_guiPush, line) end
  end
  Log.trunc = trunc
end

local function dumpTbl(t)
  if type(t) ~= "table" then return tostring(t) end
  local out = {}
  local ok = pcall(function()
    for k, v in pairs(t) do out[#out + 1] = tostring(k) .. "=" .. tostring(v) end
  end)
  return "{ " .. table.concat(out, "; ") .. " }"
end

function Log.net(kind, url, method, body, headers)
  local full = string.format(
    "===== NET CAPTURE =====\nkind   : %s\nurl    : %s\nmethod : %s\nheaders: %s\nbody   :\n%s\n=======================\n",
    tostring(kind), tostring(url), tostring(method), dumpTbl(headers), tostring(body))
  _netlog = _netlog .. full
  if _real_appendfile then pcall(_real_appendfile, NET_PATH, full) end
  Log.event("NET", string.format("%s url=%s method=%s", kind, tostring(url), tostring(method)),
    Log.trunc(tostring(body or "")))
end

function Log.stage(chunk, chunkname)
  if type(chunk) ~= "string" then return end
  _stageN = _stageN + 1
  _laststage = chunk
  local path = string.format("luraph_stage_%02d.lua", _stageN)
  local header = string.format("----- STAGE %02d (name=%s, %d bytes) -----\n", _stageN, tostring(chunkname or "?"), #chunk)
  _allstages = _allstages .. header .. chunk .. "\n\n"
  local saved = false
  if _real_writefile then saved = pcall(_real_writefile, path, chunk) end
  Log.event("EXEC", string.format("stage #%d captured (%d bytes, name=%s, saved=%s -> %s)", _stageN, #chunk, tostring(chunkname or "?"), tostring(saved), path))
end

function Log.copy()      if _real_setclipboard then return (pcall(_real_setclipboard, _alllog)) end return false end
function Log.copyNet()   if _real_setclipboard and #_netlog > 0 then return (pcall(_real_setclipboard, _netlog)) end return false end
function Log.copyStage() if _real_setclipboard and #_allstages > 0 then return (pcall(_real_setclipboard, _allstages)) end return false end

--// ---- экранная панель (Delta mobile) ---------------------------------------
do
  local ok = pcall(function()
    local parent = (gethui and gethui()) or game:GetService("CoreGui")
    local gui = Instance.new("ScreenGui")
    gui.Name = "LuraphLog"; gui.ResetOnSpawn = false; gui.Parent = parent
    local frame = Instance.new("Frame")
    frame.Size = UDim2.new(0, 400, 0, 340); frame.Position = UDim2.new(0, 10, 0, 10)
    frame.BackgroundColor3 = Color3.fromRGB(15, 15, 20); frame.BackgroundTransparency = 0.1
    frame.Active = true; frame.Draggable = true; frame.Parent = gui
    local title = Instance.new("TextLabel")
    title.Size = UDim2.new(1, -204, 0, 26); title.BackgroundColor3 = Color3.fromRGB(40, 40, 55)
    title.Text = "Luraph NET (тащи)"; title.TextColor3 = Color3.fromRGB(235, 235, 235)
    title.Font = Enum.Font.Code; title.TextSize = 14; title.Parent = frame
    local function mkBtn(x, label, col, cb)
      local b = Instance.new("TextButton")
      b.Size = UDim2.new(0, 66, 0, 26); b.Position = UDim2.new(1, x, 0, 0)
      b.BackgroundColor3 = col; b.Text = label; b.TextColor3 = Color3.fromRGB(245, 255, 245)
      b.Font = Enum.Font.Code; b.TextSize = 14; b.Parent = frame
      b.MouseButton1Click:Connect(function()
        local ok = cb()
        local old = b.Text; b.Text = ok and "OK!" or "empty"
        task.delay(1.2, function() b.Text = old end)
      end)
      return b
    end
    mkBtn(-204, "Log",    Color3.fromRGB(70, 120, 70),  Log.copy)
    mkBtn(-136, "Net",    Color3.fromRGB(70, 90, 140),  Log.copyNet)
    mkBtn(-68,  "Stage2", Color3.fromRGB(120, 90, 60),  Log.copyStage)
    local scroll = Instance.new("ScrollingFrame")
    scroll.Size = UDim2.new(1, -8, 1, -32); scroll.Position = UDim2.new(0, 4, 0, 30)
    scroll.BackgroundTransparency = 1; scroll.ScrollBarThickness = 6
    scroll.CanvasSize = UDim2.new(0, 0, 0, 0); scroll.AutomaticCanvasSize = Enum.AutomaticSize.Y
    scroll.Parent = frame
    local layout = Instance.new("UIListLayout"); layout.SortOrder = Enum.SortOrder.LayoutOrder; layout.Parent = scroll
    local idx = 0
    _guiPush = function(text)
      idx += 1
      local lbl = Instance.new("TextLabel")
      lbl.Size = UDim2.new(1, 0, 0, 0); lbl.AutomaticSize = Enum.AutomaticSize.Y
      lbl.BackgroundTransparency = 1; lbl.Text = text; lbl.TextWrapped = true
      lbl.TextXAlignment = Enum.TextXAlignment.Left; lbl.TextColor3 = Color3.fromRGB(200, 255, 200)
      lbl.Font = Enum.Font.Code; lbl.TextSize = 12; lbl.LayoutOrder = idx; lbl.Parent = scroll
    end
  end)
  if not ok then _guiPush = nil end
end

--// ---- заглушки сети/loadstring ---------------------------------------------
local function fakeResp()
  return { Success = true, StatusCode = 200, StatusMessage = "OK", Body = "", Headers = {} }
end
local function stub_loadstring(chunk, chunkname)
  Log.stage(chunk, chunkname)
  if CONFIG.run_stages and type(chunk) == "string" then
    local f, e = realLoadstring(chunk, chunkname or "=luraph_stage")
    if f then
      Log.event("EXEC", "stage recompiled -> ВЫПОЛНЯЕТСЯ (сеть блокирована)")
      return f
    end
    Log.event("WARN", "stage recompile failed: " .. tostring(e))
    return function() end
  end
  Log.event("EXEC", "loadstring/load INTERCEPTED (NOT executed) name=" .. tostring(chunkname or "?"))
  return function() Log.event("EXEC", "next-stage invocation BLOCKED"); return nil end
end

--// ---- глобальные перехваты -------------------------------------------------
local function setG(name, val)
  local ok = pcall(function() realG[name] = val end)
  if not ok and hookfunction and type(rawget(realG, name)) == "function" then
    pcall(hookfunction, rawget(realG, name), val)
  end
  return ok
end

local function req_stub(opts, ...)
  local o = opts
  if type(o) == "table" then
    Log.net("global request", o.Url or o.url, o.Method or o.method or "GET", o.Body or o.body, o.Headers or o.headers)
  else
    Log.net("global request", o, "?", nil, nil)
  end
  return fakeResp()
end

setG("request", req_stub)
setG("http_request", req_stub)
setG("loadstring", stub_loadstring)
setG("load", stub_loadstring)
setG("setclipboard", function(v) Log.event("CLIP", "setclipboard BLOCKED", Log.trunc(tostring(v))) end)
setG("toclipboard", function(v) Log.event("CLIP", "setclipboard BLOCKED", Log.trunc(tostring(v))) end)
setG("writefile", function(p, d) Log.event("FS", "writefile BLOCKED", tostring(p), Log.trunc(tostring(d))) end)
setG("appendfile", function(p, d) Log.event("FS", "appendfile BLOCKED", tostring(p)) end)
setG("delfile", function(p) Log.event("FS", "delfile BLOCKED", tostring(p)) end)
setG("makefolder", function(p) Log.event("FS", "makefolder BLOCKED", tostring(p)) end)
pcall(function()
  local syn = rawget(realG, "syn")
  if type(syn) == "table" then pcall(function() syn.request = req_stub end) end
  local http = rawget(realG, "http")
  if type(http) == "table" then pcall(function() http.request = req_stub end) end
end)

--// ---- namecall hook (методы на game / HttpService) -------------------------
local hookInfo = "skipped"
pcall(function()
  local hmm = hookmetamethod
  local gnm = getnamecallmethod
  local ncc = newcclosure or function(f) return f end
  assert(type(hmm) == "function" and type(gnm) == "function", "нет hookmetamethod/getnamecallmethod")
  local old
  old = hmm(game, "__namecall", ncc(function(self, ...)
    local m = tostring(gnm())
    if m == "HttpGet" or m == "HttpGetAsync" then
      local url = (...)
      Log.net("game:" .. m, url, "GET", nil, nil)
      if CONFIG.block_network then return "" end
      return old(self, ...)
    elseif m == "HttpPost" or m == "HttpPostAsync" then
      local url, body = ...
      Log.net("game:" .. m, url, "POST", body, nil)
      if CONFIG.block_network then return "" end
      return old(self, ...)
    elseif m == "RequestAsync" then
      local o = (...) or {}
      Log.net("HttpService:RequestAsync", o.Url, o.Method or "GET", o.Body, o.Headers)
      if CONFIG.block_network then return fakeResp() end
      return old(self, ...)
    elseif m == "GetAsync" then
      Log.net("HttpService:GetAsync", (...), "GET", nil, nil)
      if CONFIG.block_network then return "" end
      return old(self, ...)
    elseif m == "PostAsync" then
      local url, body = ...
      Log.net("HttpService:PostAsync", url, "POST", body, nil)
      if CONFIG.block_network then return "" end
      return old(self, ...)
    end
    return old(self, ...)
  end))
  hookInfo = "installed"
end)

--// ---- запуск ---------------------------------------------------------------
Log.event("INFO", "=== Luraph sandbox start (executor) ===")
Log.event("INFO", "namecall hook: " .. hookInfo .. "; block_network=" .. tostring(CONFIG.block_network))
assert(type(realLoadstring) == "function", "нет loadstring -- нужен экзекутор с loadstring")
local chunk, err = realLoadstring(EMBEDDED_SRC, "=luraph_target")
if not chunk then
  Log.event("WARN", "compile error: " .. tostring(err))
  return
end
Log.event("INFO", ("target compiled: %d bytes"):format(#EMBEDDED_SRC))
local ok, res = pcall(chunk)
if ok then
  Log.event("INFO", "target returned without error")
else
  Log.event("WARN", "target raised: " .. tostring(res))
end
Log.event("INFO", "=== Luraph sandbox end ===")
Log.event("INFO", "[NET] = URL/тело запросов; кнопка Net копирует их целиком, Stage2 -- перехваченный код.")
